OnOpenPage()

{

	// Add your component and variables initialization code here

	// WARNING: All variables definied on this function are global for this page

   if(IsProject()==0)   

   {

//      int textMode=0;

      CString parentWnd;

   }

   int textMode=0;



   int move=0;

   int mOn=0;



   LoadGroup("Cursors.grp");

   SetCursor(0);

   Panorama.OpenPanorama(0);



//#############################################################################

   int toolbar=0;

   int toolbarCase=0;

   int toolbarPhase=0;

   int txtHotSpotOn=0;

   int playStatus=0;

   int puzzleNo=0;

   Group.HotSpot_Holder.DisableHotSpot(1);

//############################################################################



   Sound_Holder.PlayDSound(14);

   SetTextMode();

   FadeScreen(1,1000);

//   SetTimer(5000);

}



void SetTextMode(void)

{

   if(textMode)

   {

      DisableScreen();

      Panorama.SetZoom(1);

      Panorama.SetHorAngle(0);

      Panorama.SetVertOffset(1000);



      playStatus = 1;

      Sound_Holder.SetPlayDSoundParameters(14,-1000,0,0);

      Sound_Holder.PlayDSound(0);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

      Panorama.Disable();

      EnableScreen();

      ShowBuffer();

   }

   else

   {

      playStatus = 0;

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(14,0,0,0);

      Panorama.Enable();

   }

}



void OnClosePage(void)

{

	// Add your close page handler code here



}







void Panorama.SpriteMouseMoveIn(int panoramaNo,int spriteNo)

{

   SetCursor(1);

   mOn=1;

}





void Panorama.SpriteMouseMoveOut()

{

   mOn=0;

   if(move)   SetCursor(move);

   else       SetCursor(0);

}







void Panorama.ClickOnSprite(int panoramaNo,int spriteNo)

{

   Sound_Holder.PlayDSound(spriteNo+1);

}





void Panorama.SpriteEndAnimation(int panoramaNo,int spriteNo)

{

   Panorama.ResetSprite(spriteNo);

}





